import React from 'react';
import { Link } from 'react-router-dom';

const Header = () => {
  return (
    <header className="header">
      {/* Centered Logo */}
      <div className="logo-container">
        <Link to="/">
          <img 
            src="/logo.PNG" 
            alt="CLICKaLINKS - Multi-Page Advertising Platform" 
            className="logo"
          />
        </Link>
      </div>
      
      {/* Page Navigation Boxes - Horizontal */}
      <div className="page-navigation">
        <Link to="/" className="page-box">Page 1</Link>
        <Link to="/page2" className="page-box">Page 2</Link>
        <Link to="/page3" className="page-box">Page 3</Link>
        <Link to="/page4" className="page-box">Page 4</Link>
        <Link to="/page5" className="page-box">Page 5</Link>
        <Link to="/page6" className="page-box">Page 6</Link>
        <Link to="/page7" className="page-box">Page 7</Link>
        <Link to="/page8" className="page-box">Page 8</Link>
        <Link to="/page9" className="page-box">Page 9</Link>
        <Link to="/page10" className="page-box">Page 10</Link>
      </div>
    </header>
  );
};

export default Header;
